CREATE OR REPLACE FUNCTION fpa_com_get_memno_from_string (as_string text,ai_row integer) RETURNS varchar AS $body$
DECLARE

  type tab_str is table of varchar(1000) index by integer;ltab_str tab_str;
  ls_string char(1);
  li_count integer;
  li_pos integer;
  li_item integer;
  ls_cutsting varchar(1000);
  ls_return char(10);

BEGIN
   ls_string := ',';
   if (as_string IS NOT NULL AND as_string::text <> '') then
    li_count := 0;
    li_pos := 1;
    li_item := position(ls_string in as_string);
    while li_item > 0 loop
      ls_cutsting := substr(as_string,li_pos,li_item - li_pos);
      li_count := li_count + 1;
      ltab_str(li_count) := ls_cutsting;
      li_pos  := li_item + length(ls_string);
      li_item := instr(as_string,ls_string,li_item + 1 );
    end  loop;
    if li_pos <= length(as_string)  then
      ls_cutsting := substr(as_string,li_pos,length(as_string) - li_pos + length(ls_string) );
      li_count := li_count + 1;
      ltab_str(li_count) := ls_cutsting;
    end if;
  end if;
    --
  li_count := 0;
  li_count := ltab_str.count;

  if ai_row > li_count then
    ls_return := null;
  else
    ls_return := ltab_str(ai_row);
  end if;


RETURN ls_return;

exception when others then CALL spa_dberror('FPA_COM_GET_MEMNO_FROM_STRING');
END;
$body$
